// Универсальный парсер from email из любого формата IMAP output.
// Поддерживает: string, object с .text, object с .value[], headers.from, fromAddress.

function extractEmailAndName(rawFromField) {
  // rawFromField может быть string, object, array
  let raw = '';

  if (!rawFromField) return { email: '', name: '' };

  if (typeof rawFromField === 'string') {
    raw = rawFromField;
  } else if (Array.isArray(rawFromField)) {
    // Иногда from = [{ address: 'x@y', name: 'Name' }]
    if (rawFromField.length > 0) {
      const first = rawFromField[0];
      if (first.address) {
        return { email: String(first.address).toLowerCase().trim(), name: String(first.name || '').trim() };
      }
      raw = String(first);
    }
  } else if (typeof rawFromField === 'object') {
    // Иногда { value: [{ address, name }] } или { text: 'Name <x@y>' } или { address, name }
    if (rawFromField.address) {
      return { email: String(rawFromField.address).toLowerCase().trim(), name: String(rawFromField.name || '').trim() };
    }
    if (rawFromField.value && Array.isArray(rawFromField.value) && rawFromField.value.length > 0) {
      const v = rawFromField.value[0];
      if (v.address) {
        return { email: String(v.address).toLowerCase().trim(), name: String(v.name || '').trim() };
      }
    }
    if (rawFromField.text) {
      raw = String(rawFromField.text);
    }
  }

  if (!raw) return { email: '', name: '' };

  // Парсим "Name <email@x.com>" или "email@x.com"
  const m = raw.match(/<([^>]+)>/);
  if (m) {
    return {
      email: m[1].toLowerCase().trim(),
      name: raw.replace(/<[^>]+>/, '').replace(/["']/g, '').trim()
    };
  }
  return {
    email: raw.toLowerCase().trim(),
    name: ''
  };
}

const items = $input.all();
const result = [];

const hardBlacklist = [
  'noreply', 'no-reply', 'donotreply', 'do-not-reply',
  'mailer-daemon', 'postmaster',
  'security-noreply', 'security@google',
  'accounts.google.com',
  'github.com', 'githubusercontent.com',
  'chatgpt.com', 'openai.com'
];

for (const item of items) {
  const data = item.json || {};

  // Пробуем разные места где может быть from
  let fromField = data.from
    || (data.headers && (data.headers.from || data.headers.From))
    || data.fromAddress
    || data.sender
    || '';

  const { email: fromEmail, name: fromName } = extractEmailAndName(fromField);

  const subject = (data.subject || data.Subject || '').toString();
  const textBody = (data.text || data.textPlain || '').toString();
  const htmlBody = (data.html || data.textHtml || '').toString();
  const stripped = htmlBody.replace(/<[^>]+>/g, ' ').replace(/\s+/g, ' ').trim();
  const bodyForClaude = textBody.length > 50 ? textBody : stripped;

  let uid = '';
  if (data.uid) uid = data.uid.toString();
  else if (data.attributes && data.attributes.uid) uid = data.attributes.uid.toString();
  else if (data.attrs && data.attrs.uid) uid = data.attrs.uid.toString();
  else if (data.messageId) uid = data.messageId.toString();
  else if (data['message-id']) uid = data['message-id'].toString();

  if (!fromEmail || !fromEmail.includes('@')) continue;

  let skip = false;
  for (const bl of hardBlacklist) {
    if (fromEmail.includes(bl)) { skip = true; break; }
  }
  if (skip) continue;

  if (!bodyForClaude || bodyForClaude.length < 5) continue;

  const receivedAt = (data.date || data.Date || new Date().toISOString()).toString();

  result.push({
    json: {
      from_email: fromEmail,
      from_name: fromName,
      subject: subject,
      body: bodyForClaude.substring(0, 4000),
      received_at: receivedAt,
      imap_uid: uid
    }
  });
}

// Если 0 прошло - отдаем ОЧЕНЬ подробный debug item с ключами первого input item
if (result.length === 0) {
  const debugInfo = {
    _debug: true,
    _info: 'no emails passed filter',
    from_email: '',
    _input_count: items.length
  };

  if (items.length > 0) {
    const sample = items[0].json || {};
    debugInfo._sample_keys = Object.keys(sample).slice(0, 30);
    debugInfo._sample_from_raw = JSON.stringify(sample.from || sample.From || sample.headers?.from || 'NOT_FOUND').substring(0, 500);
    debugInfo._sample_subject = (sample.subject || sample.Subject || 'NO_SUBJECT').toString().substring(0, 200);
    debugInfo._sample_uid = String(sample.uid || sample.attributes?.uid || 'NO_UID');
    debugInfo._sample_has_text = !!sample.text;
    debugInfo._sample_has_html = !!sample.html;
    debugInfo._sample_has_headers = !!sample.headers;
  }

  return [{ json: debugInfo }];
}

return result;

// Сопоставляет входящие письма с отправленными outreach.
// Дедупит по imap_uid (чтобы одно письмо не обработать дважды).
// Также проверяет Suppression лист - если email там, не обрабатываем.
// Возвращает только новые matched письма.

function flattenRows(items) {
  const out = [];
  for (const it of items) {
    const j = it.json;
    if (!j) continue;
    if (Array.isArray(j)) {
      for (const row of j) out.push(row);
    } else {
      out.push(j);
    }
  }
  return out;
}

const emails = $('Filter Whitelist').all();
const outreachRows = flattenRows($('Get Outreach Sheet').all());
const repliesRows = flattenRows($('Get Replies Sheet').all());

// Indexed lookups
const sentByEmail = new Map();
for (const r of outreachRows) {
  if (r && r.email && r.status === 'sent') {
    sentByEmail.set(String(r.email).toLowerCase().trim(), r);
  }
}

const processedUIDs = new Set();
for (const r of repliesRows) {
  if (r && r.imap_uid != null) {
    processedUIDs.add(String(r.imap_uid));
  }
}

const matches = [];

for (const item of emails) {
  const j = item.json;
  if (!j) continue;

  const fromEmail = String(j.from_email || '').toLowerCase().trim();
  const fromName = j.from_name || j.from_email || '';
  const uid = j.imap_uid != null ? String(j.imap_uid) : '';

  if (!fromEmail) continue;
  if (uid && processedUIDs.has(uid)) continue;

  const sentRow = sentByEmail.get(fromEmail);
  if (!sentRow) continue;

  matches.push({
    json: {
      from_email: fromEmail,
      from_name: fromName,
      reply_subject: j.subject || '',
      reply_body: j.body || '',
      received_at: j.date || new Date().toISOString(),
      imap_uid: uid,
      outreach_website: sentRow.website || '',
      company_name: sentRow.company_name || '',
      city: sentRow.city || '',
      country: sentRow.country || '',
      language: sentRow.language || 'en',
      score: sentRow.score || 0,
    }
  });
}

return matches;

// Формирует request body для Anthropic API
// Использует ту же схему что Copywriter (claude-sonnet-4-6)

const item = $json;

const systemPrompt = `You are an email reply classifier for a B2B cold outreach campaign in real estate niche.
You analyze replies from real estate agencies and classify them into exactly ONE of 6 categories:

- positive: shows interest, asks questions about pricing/setup/demo, wants to learn more, says yes
- negative: clearly not interested, "no thanks", "not relevant", rejection
- out_of_office: vacation autoresponder, "I'm away until X"
- unsubscribe: asks to be removed, "stop emailing", "remove me", "unsubscribe", GDPR removal request
- referral: redirects to another person, "contact John instead", "talk to our marketing team"
- neutral: anything unclear, simple acknowledgment, asks unrelated question

Respond ONLY with valid JSON in this exact schema:
{
  "category": "positive|negative|out_of_office|unsubscribe|referral|neutral",
  "confidence": 0.0-1.0,
  "reason": "1 sentence in Russian explaining why",
  "key_quote": "shortest meaningful phrase from reply (max 80 chars), in original language"
}

No markdown, no preamble, ONLY raw JSON.`;

const userPrompt = [
  'Context about the lead we cold-emailed:',
  'Company: ' + (item.company_name || 'unknown'),
  'City: ' + (item.city || 'unknown'),
  'Country: ' + (item.country || 'unknown'),
  'Original lead language: ' + (item.language || 'en'),
  '',
  'Reply received:',
  'From: ' + item.from_email,
  'From name: ' + (item.from_name || 'unknown'),
  'Subject: ' + (item.reply_subject || '(no subject)'),
  '',
  'Reply body:',
  '"""',
  item.reply_body,
  '"""',
  '',
  'Classify this reply.'
].join('\n');

const requestBody = {
  model: 'claude-sonnet-4-6',
  max_tokens: 400,
  system: systemPrompt,
  messages: [
    { role: 'user', content: userPrompt }
  ]
};

return [{
  json: {
    ...item,
    _claude_body: requestBody
  }
}];

// Парсит ответ Claude, склеивает с контекстом письма
// Используем $('Build Claude Request') чтобы достать оригинальные поля

const claudeRaw = $input.first().json;
const ctx = $('Build Claude Request').item.json;

// Default значения если parsing fails
let parsed = {
  category: 'neutral',
  confidence: 0.0,
  reason: 'parse_failed',
  key_quote: ''
};

try {
  const content = (claudeRaw.content && claudeRaw.content[0] && claudeRaw.content[0].text) || '';
  const match = content.match(/\{[\s\S]*\}/);
  if (match) {
    const obj = JSON.parse(match[0]);
    parsed.category = String(obj.category || 'neutral').toLowerCase();
    parsed.confidence = Number(obj.confidence) || 0;
    parsed.reason = String(obj.reason || '').substring(0, 300);
    parsed.key_quote = String(obj.key_quote || '').substring(0, 200);
  }
} catch (e) {
  parsed.reason = 'parse_error: ' + e.message;
}

// Validate category
const validCategories = ['positive', 'negative', 'out_of_office', 'unsubscribe', 'referral', 'neutral'];
if (!validCategories.includes(parsed.category)) {
  parsed.category = 'neutral';
}

return [{
  json: {
    received_at: ctx.received_at,
    from_email: ctx.from_email,
    from_name: ctx.from_name,
    outreach_website: ctx.outreach_website,
    reply_subject: ctx.reply_subject,
    reply_body: ctx.reply_body,
    category: parsed.category,
    confidence: parsed.confidence,
    reason: parsed.reason,
    key_quote: parsed.key_quote,
    imap_uid: ctx.imap_uid,
    // Контекст для Telegram alert
    _company_name: ctx.company_name,
    _city: ctx.city,
    _country: ctx.country,
    _language: ctx.language
  }
}];

// Формирует HTML сообщение для Telegram
// parse_mode = HTML
// ВАЖНО: данные берем из Parse Claude Response, потому что $json это output от Update Outreach (только website+status)

const r = $('Parse Claude Response').item.json;

// Эмодзи и заголовок по категории
let emoji = '';
let title = '';
let actionLine = '';

if (r.category === 'positive') {
  emoji = '🔥';
  title = 'Горячий лид, заинтересовался';
  actionLine = '<b>Что делать:</b> ответить лично в течение 1 часа, пока теплый';
} else if (r.category === 'referral') {
  emoji = '↪️';
  title = 'Перенаправление на другого человека';
  actionLine = '<b>Что делать:</b> уточнить контакт нужного человека и написать ему';
}

// Country flag
const flagMap = {
  'NL': '🇳🇱', 'PL': '🇵🇱', 'CZ': '🇨🇿',
  'DE': '🇩🇪', 'FR': '🇫🇷', 'ES': '🇪🇸',
  'IT': '🇮🇹', 'BE': '🇧🇪', 'AT': '🇦🇹',
  'GB': '🇬🇧', 'IE': '🇮🇪', 'CH': '🇨🇭'
};
const country = (r._country || '').toString().toUpperCase();
const flag = flagMap[country] || '🌍';

// HTML escape
function esc(s) {
  return String(s == null ? '' : s)
    .replace(/&/g, '&amp;')
    .replace(/</g, '&lt;')
    .replace(/>/g, '&gt;');
}

const company = esc(r._company_name) || '<i>(без названия)</i>';
const city = esc(r._city) || '—';
const fromName = esc(r.from_name);
const fromEmail = esc(r.from_email);
const subject = esc(r.reply_subject) || '<i>(без темы)</i>';

// Превью ответа: первые 250 символов
const replyText = String(r.reply_body || '').replace(/\s+/g, ' ').trim();
const truncated = replyText.length > 250;
const replyPreview = esc(replyText.substring(0, 250)) + (truncated ? '...' : '');

const reason = esc(r.reason || '');
const keyQuote = esc(r.key_quote || '');
const confidencePercent = Math.round((Number(r.confidence) || 0) * 100);

const message = `${emoji} <b>${title}</b>

<b>Компания:</b> ${company}
<b>Город:</b> ${flag} ${city}
<b>От кого:</b> ${fromName} &lt;${fromEmail}&gt;

<b>Тема:</b> ${subject}

<blockquote>${replyPreview}</blockquote>

<b>AI анализ:</b> ${reason}
<b>Уверенность:</b> ${confidencePercent}%
${keyQuote ? `<b>Ключевая фраза:</b> "<i>${keyQuote}</i>"\n` : ''}
⚡ ${actionLine}`;

return [{ json: { telegram_message: message, chat_id: 'YOUR_TELEGRAM_CHAT_ID' } }];
